import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import './App.css';

const AuthScreen = ({ onLogin, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');
  const [name, setName] = useState('');

  return (
    <div className="login-page">
      <div className="login-card fade-in">
        <div className="logo-icon">☕</div>
        <h2 className="login-title">Etika Paradise</h2>
        <p className="login-subtitle">{isLogin ? 'Вход в систему' : 'Регистрация гостя'}</p>
        <div className="auth-form">
          {!isLogin && <input type="text" placeholder="Ваше имя" className="auth-input" onChange={e => setName(e.target.value)} />}
          <input type="email" placeholder="Email" className="auth-input" onChange={e => setEmail(e.target.value)} />
          <input type="password" placeholder="Пароль" className="auth-input" onChange={e => setPass(e.target.value)} />
          <button className="btn-auth-submit" onClick={() => isLogin ? onLogin(email, pass) : onRegister(name, email, pass)}>
            {isLogin ? 'Войти' : 'Создать аккаунт'}
          </button>
        </div>
        <p className="toggle-auth" onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Нет аккаунта? Регистрация' : 'Уже есть аккаунт? Войти'}
        </p>
      </div>
    </div>
  );
};

const Menu = ({ cart, onAddToCart, onOrder }) => {
  const categories = [
    { name: 'Кофе', items: [
      { id: 1, name: 'Капучино', price: 250, img: '☕', desc: 'Классический баланс' },
      { id: 2, name: 'Латте', price: 280, img: '🥛', desc: 'Много молока, мало кофе' },
      { id: 5, name: 'Флэт Уайт', price: 310, img: '🍶', desc: 'Насыщенный вкус' }
    ]},
    { name: 'Еда', items: [
      { id: 3, name: 'Круассан', price: 210, img: '🥐', desc: 'Сливочный и хрустящий' },
      { id: 4, name: 'Сэндвич', price: 350, img: '🥪', desc: 'С индейкой и сыром' }
    ]}
  ];
  const total = cart.reduce((sum, i) => sum + i.price, 0);

  return (
    <div className="page fade-in">
      <header className="menu-header">
        <h2>Paradise Menu</h2>
        <p className="date-display">{new Date().toLocaleDateString('ru-RU', { weekday: 'long', day: 'numeric', month: 'short' })}</p>
      </header>
      {categories.map(cat => (
        <div key={cat.name} className="category-section">
          <h3 className="category-title">{cat.name}</h3>
          <div className="product-grid">
            {cat.items.map(i => (
              <div key={i.id} className="product-card">
                <div className="product-emoji">{i.img}</div>
                <div className="product-info">
                  <div className="name-price"><h4>{i.name}</h4><span className="price-tag">{i.price} ₽</span></div>
                  <p className="product-desc">{i.desc}</p>
                </div>
                <button className="btn-add-minimal" onClick={() => onAddToCart(i)}>+</button>
              </div>
            ))}
          </div>
        </div>
      ))}
      {cart.length > 0 && (
        <div className="cart-floating fade-in">
          <div className="cart-content">
            <div className="cart-text"><span>{cart.length} позиции</span><strong>{total} ₽</strong></div>
            <button className="btn-order-now" onClick={onOrder}>Оформить</button>
          </div>
        </div>
      )}
    </div>
  );
};

const Profile = ({ user, orders, onLogout }) => {
  const formatDate = (ds) => new Date(ds).toLocaleDateString('ru-RU', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' });
  return (
    <div className="page fade-in">
      <div className="profile-header">
        <div><span className="welcome">Привет,</span><h2 className="user-name">{user?.company_name}</h2></div>
        <button onClick={onLogout} className="btn-logout-minimal">Выйти</button>
      </div>
      <h3>История заказов</h3>
      <div className="order-list">
        {orders.map(o => (
          <div key={o.id} className="order-card-compact">
            <div className="order-top"><span>{formatDate(o.created_at)}</span><span>{o.total_amount} ₽</span></div>
            <p className="o-desc">#{o.id} — {o.description}</p>
            <div className={`status-pill ${o.status === 'Готов' || o.status === 'Выдан' ? 'active' : ''}`}>{o.status}</div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [orders, setOrders] = useState([]);
  const [cart, setCart] = useState([]);
  const loc = useLocation();

  useEffect(() => {
    if (!user) return;
    const fetchOrders = () => fetch(`http://localhost:8000/index.php?user_id=${user.id}`).then(res => res.json()).then(setOrders);
    fetchOrders();
    const int = setInterval(fetchOrders, 4000);
    return () => clearInterval(int);
  }, [user]);

  const auth = async (action, body) => {
    const res = await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ action, ...body })});
    const data = await res.json();
    if (data.id) { setUser(data); localStorage.setItem('user', JSON.stringify(data)); } else alert(data.error);
  };

  if (!user) return <AuthScreen onLogin={(email, password) => auth('login', { email, password })} onRegister={(name, email, password) => auth('register', { name, email, password })} />;

  return (
    <div className="paradise-app">
      <Routes>
        <Route path="/" element={<Menu cart={cart} onAddToCart={i => setCart([...cart, i])} onOrder={async () => {
          await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ user_id: user.id, description: cart.map(i => i.name).join(', '), total_amount: cart.reduce((s, i) => s + i.price, 0) })});
          setCart([]); alert('Заказ принят!');
        }} />} />
        <Route path="/profile" element={<Profile user={user} orders={orders} onLogout={() => {setUser(null); localStorage.removeItem('user');}} />} />
      </Routes>
      <nav className="bottom-bar">
        <Link to="/" className={`nav-link ${loc.pathname === '/' ? 'active' : ''}`}><span>🍴</span> Меню</Link>
        <Link to="/profile" className={`nav-link ${loc.pathname === '/profile' ? 'active' : ''}`}><span>👤</span> Профиль</Link>
      </nav>
    </div>
  );
}
